#define MIN(a, b) ((a) <= (b) ? (a) : (b))

__kernel void dynproc_kernel(
    int arg0,
    __global const int* d_gpuWall,
    __global const int* src,
    __global int* dst,
    int cols,
    int rows,
    int t,
    int borderCols,
    int theHalo,
    __local int* local_min,
    __local int* local_src,
    __global int* d_outputBuffer)
{
    int gid = get_global_id(0);
    int lid = get_local_id(0);
    int lsize = get_local_size(0);

    if (gid >= cols) return;

    // Load source data into local memory for faster access
    local_src[lid] = src[gid];
    barrier(CLK_LOCAL_MEM_FENCE);

    int min_val = local_src[lid];

    // Check left neighbor
    if (gid > 0) {
        int left_val = (lid > 0) ? local_src[lid - 1] : src[gid - 1];
        min_val = MIN(min_val, left_val);
    }

    // Check right neighbor
    if (gid < cols - 1) {
        int right_val = (lid < lsize - 1) ? local_src[lid + 1] : src[gid + 1];
        min_val = MIN(min_val, right_val);
    }

    // Calculate new value: wall[t+1][gid] + min_neighbor
    // d_gpuWall is offset by 'cols' in the host code, so index is (t * cols) + gid
    int wall_val = d_gpuWall[t * cols + gid];
    dst[gid] = wall_val + min_val;
}
